-- ─── Dataset metadata (34 statistics — no observations) ─────────────────────

INSERT INTO datasets (
    slug, stat_id, name, description, category_id, source_id,
    unit, cadence, automation_level, geographic_level,
    publication_name, source_url, notes, series_start_label, series_end_label
) VALUES
    ('unemployment', 'unemployment-national', 'National Unemployment Rate', 'South Africa''s official unemployment rate fell to 31.4% in Q4 2025 — the lowest since Q2 2022 — as 44,000 more people found work. The number of employed persons rose to 17.1 million. The expanded unemployment rate (including discouraged work-seekers) stands at 40.7%.', 'unemployment', 1, '%', 'quarterly', 'semi-auto', 'national', 'Quarterly Labour Force Survey Q4 2025', 'https://www.statssa.gov.za/?page_id=1854&PPN=P0211', 'Official unemployment uses ILO strict definition. Expanded definition includes discouraged work-seekers. Q4 2025 data published Feb 2026 showing 31.4%. Provincial data from same QLFS release. Update by running: python scripts/update_unemployment.py', 'Q1 2022', 'Q4 2025'),
    ('unemployment', 'youth-unemployment', 'Youth Unemployment (15–34)', 'Youth unemployment (ages 15–34) declined to 44.8% in Q4 2025. Among those aged 15–24, the rate stands at 61.4% — meaning roughly 6 in 10 young South Africans who want work cannot find it. South Africa''s youth unemployment is among the highest globally.', 'unemployment', 1, '%', 'quarterly', 'semi-auto', 'national', 'Quarterly Labour Force Survey Q4 2025', 'https://www.statssa.gov.za/?page_id=1854&PPN=P0211', 'Official unemployment uses ILO strict definition. Expanded definition includes discouraged work-seekers. Q4 2025 data published Feb 2026 showing 31.4%. Provincial data from same QLFS release. Update by running: python scripts/update_unemployment.py', 'Q1 2022', 'Q4 2025'),
    ('unemployment', 'labour-force-participation', 'Labour Force Participation Rate', '42.7% of working-age South Africans (ages 15–64) were either employed or actively seeking work in Q4 2025. This participation rate remains among the lowest globally, partly reflecting large numbers of discouraged work-seekers who have given up looking for jobs.', 'unemployment', 1, '%', 'quarterly', 'semi-auto', 'national', 'Quarterly Labour Force Survey Q4 2025', 'https://www.statssa.gov.za/?page_id=1854&PPN=P0211', 'Official unemployment uses ILO strict definition. Expanded definition includes discouraged work-seekers. Q4 2025 data published Feb 2026 showing 31.4%. Provincial data from same QLFS release. Update by running: python scripts/update_unemployment.py', 'Q1 2023', 'Q4 2025'),
    ('youth-unemployment', 'youth-unemployment-narrow', 'Youth Unemployment Rate (15–34)', 'Narrow youth unemployment rate for those aged 15–34 who are without work, available for work, and actively seeking employment.', 'unemployment', 1, '%', 'quarterly', 'semi-auto', 'national', NULL, 'https://www.statssa.gov.za/?page_id=1854&PPN=P0211', 'Youth unemployment (ages 15–34) from QLFS Q4 2025. SA has one of the highest youth unemployment rates globally. The expanded rate includes discouraged work-seekers and is particularly high among 15–24 year olds.', 'Q1 2022', 'Q4 2025'),
    ('youth-unemployment', 'youth-unemployment-1524', 'Youth Unemployment Rate (15–24)', 'Unemployment rate among 15–24 year olds — among the highest in the world. This cohort faces structural barriers including lack of experience, skills mismatch, and geographic concentration of youth outside economic centres.', 'unemployment', 1, '%', 'quarterly', 'semi-auto', 'national', NULL, 'https://www.statssa.gov.za/?page_id=1854&PPN=P0211', 'Youth unemployment (ages 15–34) from QLFS Q4 2025. SA has one of the highest youth unemployment rates globally. The expanded rate includes discouraged work-seekers and is particularly high among 15–24 year olds.', 'Q1 2022', 'Q4 2025'),
    ('youth-unemployment', 'youth-unemployment-expanded', 'Youth Unemployment — Expanded (15–34)', 'The expanded youth unemployment rate includes discouraged work-seekers — those who have given up actively looking for work. This is a more comprehensive measure of labour market distress among youth.', 'unemployment', 1, '%', 'quarterly', 'semi-auto', 'national', NULL, 'https://www.statssa.gov.za/?page_id=1854&PPN=P0211', 'Youth unemployment (ages 15–34) from QLFS Q4 2025. SA has one of the highest youth unemployment rates globally. The expanded rate includes discouraged work-seekers and is particularly high among 15–24 year olds.', 'Q1 2022', 'Q4 2025'),
    ('youth-unemployment', 'youth-neet-rate', 'NEET Rate (15–24)', 'Percentage of youth aged 15–24 who are Not in Employment, Education, or Training (NEET). This captures both unemployment and disengagement from the education system — a key indicator of social exclusion risk.', 'unemployment', 1, '%', 'quarterly', 'semi-auto', 'national', NULL, 'https://www.statssa.gov.za/?page_id=1854&PPN=P0211', 'Youth unemployment (ages 15–34) from QLFS Q4 2025. SA has one of the highest youth unemployment rates globally. The expanded rate includes discouraged work-seekers and is particularly high among 15–24 year olds.', '2019', '2025'),
    ('labour-force', 'lfpr-overall', 'Labour Force Participation Rate', 'The labour force participation rate (LFPR) is the percentage of the working-age population (15–64) that is economically active — either employed or actively looking for work. South Africa''s LFPR remains among the lowest of comparable middle-income countries, partly due to high rates of discouragement.', 'unemployment', 1, '%', 'quarterly', 'semi-auto', 'national', 'Quarterly Labour Force Survey Q4 2025', 'https://www.statssa.gov.za/?page_id=1854&PPN=P0211', 'Labour force participation rate (LFPR) measures the share of the working-age population (15–64) that is either employed or actively looking for work. South Africa''s LFPR is low by international standards, partly reflecting high rates of discouragement.', 'Q1 2020', 'Q4 2025'),
    ('labour-force', 'female-labour-participation', 'Female Labour Force Participation Rate', 'Labour force participation rate for women aged 15–64. The gender gap in participation (about 10 percentage points) reflects structural barriers including care responsibilities, transport access, and sectoral concentration.', 'unemployment', 1, '%', 'quarterly', 'semi-auto', 'national', 'Quarterly Labour Force Survey Q4 2025', 'https://www.statssa.gov.za/?page_id=1854&PPN=P0211', 'Labour force participation rate (LFPR) measures the share of the working-age population (15–64) that is either employed or actively looking for work. South Africa''s LFPR is low by international standards, partly reflecting high rates of discouragement.', 'Q1 2022', 'Q4 2025'),
    ('inflation', 'cpi-headline', 'Headline Inflation (CPI)', 'South Africa''s headline CPI rose to 4.0% year-on-year in April 2026 — the steepest reading since August 2024. The main drivers were a sharp jump in fuel prices (+18% annually), higher electricity tariffs, and insurance costs. Food inflation eased to 2.9%. Core inflation (ex-food, fuel, energy) rose to 3.6%. This moves inflation above the SARB''s new 3% target midpoint.', 'inflation', 1, '%', 'monthly', 'semi-auto', 'national', 'Consumer Price Index April 2026', 'https://www.statssa.gov.za/?page_id=1854&PPN=P0141', 'CPI figures are year-on-year % change. SARB inflation target was changed to 3% (±1pp) on 12 November 2025 from the previous 3–6% band. Repo rate decisions made at MPC meetings approx. 6× per year. Update by running: python scripts/update_inflation.py', 'May 2025', 'Apr 2026'),
    ('inflation', 'food-inflation', 'Food & Non-Alcoholic Beverages CPI', 'Food and non-alcoholic beverage inflation eased to 2.9% in April 2026, continuing its decline from 2023 highs above 14%. Strong farm output has moderated food prices. Meat prices remain elevated year-on-year despite recent monthly declines. Bread and cereals saw mixed trends.', 'inflation', 1, '%', 'monthly', 'semi-auto', 'national', 'Consumer Price Index April 2026', 'https://www.statssa.gov.za/?page_id=1854&PPN=P0141', 'CPI figures are year-on-year % change. SARB inflation target was changed to 3% (±1pp) on 12 November 2025 from the previous 3–6% band. Repo rate decisions made at MPC meetings approx. 6× per year. Update by running: python scripts/update_inflation.py', 'May 2025', 'Apr 2026'),
    ('inflation', 'repo-rate', 'SARB Policy Rate (Repo Rate)', 'The SARB held the repo rate at 6.75% at the March 2026 MPC meeting — the second consecutive hold. The decision was unanimous. The MPC cited the Iran war-related oil price shock as creating upside inflation risk. The prime lending rate remains at 10.25%. The SARB''s new inflation target is 3% (±1pp), adopted November 2025.', 'inflation', 2, '%', 'monthly', 'semi-auto', 'national', 'MPC Statement March 2026', 'https://www.resbank.co.za/en/home/publications/publication-detail-pages/statements/monetary-policy-statements/2026/march', 'CPI figures are year-on-year % change. SARB inflation target was changed to 3% (±1pp) on 12 November 2025 from the previous 3–6% band. Repo rate decisions made at MPC meetings approx. 6× per year. Update by running: python scripts/update_inflation.py', 'May 2023', 'Mar 2026'),
    ('inflation', 'annual-cpi-avg', 'Annual Average CPI (Full Year)', 'South Africa''s full-year average headline CPI for 2025 was 3.2% — the lowest annual average in 21 years, confirmed by Stats SA in January 2026. This represents a dramatic improvement from 2022''s peak of 6.9% and reflects the impact of aggressive SARB rate hikes and falling global commodity prices.', 'inflation', 1, '%', 'monthly', 'semi-auto', 'national', 'Consumer Price Index December 2025', 'https://www.statssa.gov.za/?page_id=1854&PPN=P0141', 'CPI figures are year-on-year % change. SARB inflation target was changed to 3% (±1pp) on 12 November 2025 from the previous 3–6% band. Repo rate decisions made at MPC meetings approx. 6× per year. Update by running: python scripts/update_inflation.py', '2015', '2025'),
    ('gdp', 'gdp-growth', 'GDP Growth Rate (Quarter-on-Quarter)', 'South Africa''s real GDP grew 0.4% quarter-on-quarter in Q4 2025, seasonally adjusted and annualised, above expectations of 0.3%. This marked the fifth consecutive quarter of expansion. Finance led growth (+1.4%), while manufacturing was the largest drag (-0.6%). For the full year 2025, GDP rose 1.1% — the strongest annual growth since 2022.', 'gdp', 1, '%', 'quarterly', 'semi-auto', 'national', 'Gross Domestic Product Q4 2025', 'https://www.statssa.gov.za/?page_id=1854&PPN=P0441', 'Growth rates are quarter-on-quarter, seasonally adjusted and annualised (SAAR), at constant 2015 prices. Nominal GDP is at current prices in ZAR billions. Source: Stats SA P0441 releases and SARB Quarterly Bulletin June 2025. Update by running: python scripts/update_gdp.py', 'Q1 2022', 'Q4 2025'),
    ('gdp', 'gdp-annual-growth', 'GDP Annual Growth Rate', 'South Africa''s real GDP grew 1.1% for the full year 2025, the strongest annual rate since 2022. Growth was broad-based despite ongoing headwinds from high borrowing costs and slow global demand. Manufacturing registered its second year of negative growth; construction posted its ninth straight year of decline.', 'gdp', 1, '%', 'quarterly', 'semi-auto', 'national', 'Gross Domestic Product Q4 2025', 'https://www.statssa.gov.za/?page_id=1854&PPN=P0441', 'Growth rates are quarter-on-quarter, seasonally adjusted and annualised (SAAR), at constant 2015 prices. Nominal GDP is at current prices in ZAR billions. Source: Stats SA P0441 releases and SARB Quarterly Bulletin June 2025. Update by running: python scripts/update_gdp.py', '2015', '2025'),
    ('gdp', 'gdp-nominal', 'Nominal GDP', 'South Africa''s nominal GDP for 2025 at current prices. Nominal growth reflects both real output and price-level changes. The economy remains the second largest in Africa by nominal GDP, behind Nigeria.', 'gdp', 1, 'ZAR billion', 'quarterly', 'semi-auto', 'national', 'Gross Domestic Product Q4 2025', 'https://www.statssa.gov.za/?page_id=1854&PPN=P0441', 'Growth rates are quarter-on-quarter, seasonally adjusted and annualised (SAAR), at constant 2015 prices. Nominal GDP is at current prices in ZAR billions. Source: Stats SA P0441 releases and SARB Quarterly Bulletin June 2025. Update by running: python scripts/update_gdp.py', '2018', '2025'),
    ('gdp', 'gdp-per-capita', 'GDP Per Capita', 'Nominal GDP per capita for 2025 at current prices, estimated from nominal GDP and mid-year population. In USD terms at average 2025 exchange rates (~R18.60/$), this is approximately $6,500 per person.', 'gdp', 1, 'ZAR', 'quarterly', 'semi-auto', 'national', 'Gross Domestic Product Q4 2025', 'https://www.statssa.gov.za/?page_id=1854&PPN=P0441', 'Growth rates are quarter-on-quarter, seasonally adjusted and annualised (SAAR), at constant 2015 prices. Nominal GDP is at current prices in ZAR billions. Source: Stats SA P0441 releases and SARB Quarterly Bulletin June 2025. Update by running: python scripts/update_gdp.py', '2018', '2025'),
    ('interest-rates', 'repo-rate-sarb', 'Repo Rate', 'The repurchase (repo) rate is the benchmark interest rate set by the South African Reserve Bank''s Monetary Policy Committee (MPC). It is the rate at which the SARB lends short-term money to commercial banks and is the primary instrument of inflation targeting.', 'gdp', 2, '%', 'monthly', 'semi-auto', 'national', 'MPC Statement March 2026', 'https://www.resbank.co.za/en/home/publications/publication-detail-pages/statements/monetary-policy-statements/2026/march', 'Repo rate is the rate at which the SARB lends to commercial banks. Prime lending rate = Repo + 3.5%. Both are the primary levers of South African monetary policy.', 'Jan 2022', 'Mar 2026'),
    ('interest-rates', 'prime-lending-rate', 'Prime Lending Rate', 'The prime lending rate is the benchmark rate at which commercial banks lend to their most creditworthy clients. It is conventionally set at repo rate + 3.5 percentage points. Most consumer and business loans are priced relative to prime.', 'gdp', 2, '%', 'monthly', 'semi-auto', 'national', 'MPC Statement March 2026', 'https://www.resbank.co.za/en/home/publications/publication-detail-pages/statements/monetary-policy-statements/2026/march', 'Repo rate is the rate at which the SARB lends to commercial banks. Prime lending rate = Repo + 3.5%. Both are the primary levers of South African monetary policy.', 'Jan 2022', 'Mar 2026'),
    ('crime', 'murder-rate', 'Murder Cases', 'Total murder cases reported nationally for the 2023/24 financial year (April 2023 – March 2024). This is the first decline in four years, equating to approximately 72 murders per day. The rate is 41.9 per 100,000 population.', 'crime', 4, 'cases', 'annual', 'manual', 'national', 'Crime Statistics 2023/24', 'https://www.saps.gov.za/services/crimestats.php', 'SAPS publishes crime stats once per year in September. No public API. Data must be manually extracted from the published Excel workbooks. Latest available: 2023/24. Update by running: python scripts/update_crime.py (manual step required — see script comments)', '2017/18', '2023/24'),
    ('crime', 'crime-contact', 'Contact Crimes (Total)', 'Contact crimes include assault GBH, common assault, robbery with aggravating circumstances, common robbery, sexual offences, and murder. Total contact crimes declined for the 2023/24 reporting period.', 'crime', 4, 'cases', 'annual', 'manual', 'national', 'Crime Statistics 2023/24', 'https://www.saps.gov.za/services/crimestats.php', 'SAPS publishes crime stats once per year in September. No public API. Data must be manually extracted from the published Excel workbooks. Latest available: 2023/24. Update by running: python scripts/update_crime.py (manual step required — see script comments)', '2019/20', '2023/24'),
    ('crime', 'crime-robbery', 'Robbery with Aggravating Circumstances', 'Robberies involving a weapon, violence, or the threat of violence for the 2023/24 financial year. This category includes carjacking, truck hijacking, house robbery, and bank robbery.', 'crime', 4, 'cases', 'annual', 'manual', 'national', 'Crime Statistics 2023/24', 'https://www.saps.gov.za/services/crimestats.php', 'SAPS publishes crime stats once per year in September. No public API. Data must be manually extracted from the published Excel workbooks. Latest available: 2023/24. Update by running: python scripts/update_crime.py (manual step required — see script comments)', '2019/20', '2023/24'),
    ('education', 'matric-pass-rate', 'National Matric Pass Rate', 'The national senior certificate (matric) pass rate for the 2024 academic year, the highest on record. Bachelor''s degree passes (qualifying for university entrance) were achieved by 47.8% of candidates. 1,044,415 candidates wrote the examinations.', 'education', 3, '%', 'decennial', 'manual', 'national', 'NSC Examination Results 2024', 'https://www.education.gov.za/Informationfor/Examinationsresults.aspx', 'Matric pass rates are published in January each year. Literacy rates come from Census (10-year cycle). Update matric results by running: python scripts/update_education.py', '2015', '2024'),
    ('education', 'education-literacy', 'Adult Literacy Rate (20+)', 'Proportion of adults aged 20 and older who can read and write, as recorded in the 2022 National Census. This represents significant improvement from 85.0% in 2011. The next census is expected in 2032.', 'education', 1, '%', 'decennial', 'manual', 'national', 'Census 2022 Statistical Release', 'https://www.statssa.gov.za/census/census_2022/census_2022_products/Census_2022_Statistical_release.pdf', 'Matric pass rates are published in January each year. Literacy rates come from Census (10-year cycle). Update matric results by running: python scripts/update_education.py', NULL, NULL),
    ('education', 'higher-education-enrolment', 'Higher Education Enrolment', 'Total headcount enrolments at public universities for the 2023 academic year, across 26 public higher education institutions. This excludes TVET colleges and private higher education institutions.', 'education', 1, 'students', 'decennial', 'manual', 'national', 'Statistics on Post-School Education and Training 2023', 'https://www.dhet.gov.za/Management%20Information%20Systems/Statistics%20on%20Post-School%20Education%20and%20Training%20in%20South%20Africa%202023.pdf', 'Matric pass rates are published in January each year. Literacy rates come from Census (10-year cycle). Update matric results by running: python scripts/update_education.py', '2018', '2023'),
    ('population', 'population-total', 'Total Population', 'South Africa''s estimated total population for mid-2024, based on Stats SA''s mid-year population estimates. The 2022 Census counted 62.0 million. Annual population growth is estimated at approximately 1.4%.', 'population', 1, 'people', 'decennial', 'auto', 'national', 'Mid-Year Population Estimates 2024', 'https://www.statssa.gov.za/?page_id=1854&PPN=P0302', 'Census 2022 is the definitive source. Mid-year estimates (P0302) are published annually in July and provide intercensal estimates. Update by running: python scripts/update_population.py', '2015', '2024'),
    ('population', 'population-urban', 'Urban Population Share', 'Percentage of the population living in urban areas, as recorded in Census 2022. Gauteng alone accounts for over a quarter of South Africa''s population. The Northern Cape remains the least densely populated province.', 'population', 1, '%', 'decennial', 'auto', 'national', 'Census 2022 Statistical Release', 'https://www.statssa.gov.za/census/census_2022/census_2022_products/Census_2022_Statistical_release.pdf', 'Census 2022 is the definitive source. Mid-year estimates (P0302) are published annually in July and provide intercensal estimates. Update by running: python scripts/update_population.py', NULL, NULL),
    ('population', 'population-median-age', 'Median Age', 'The median age of the South African population as measured in Census 2022. At 28 years, South Africa has a relatively young population, with significant implications for labour markets, education, and social services.', 'population', 1, 'years', 'decennial', 'auto', 'national', 'Census 2022 Statistical Release', 'https://www.statssa.gov.za/census/census_2022/census_2022_products/Census_2022_Statistical_release.pdf', 'Census 2022 is the definitive source. Mid-year estimates (P0302) are published annually in July and provide intercensal estimates. Update by running: python scripts/update_population.py', NULL, NULL),
    ('housing', 'housing-access-piped-water', 'Access to Piped Water (In-dwelling)', 'Percentage of households with access to piped water inside their dwelling as per Census 2022. Rural provinces continue to lag significantly — Limpopo (38%) and Eastern Cape (42%) have the lowest access rates.', 'housing', 1, '%', 'decennial', 'manual', 'national', 'Census 2022 Statistical Release', 'https://www.statssa.gov.za/census/census_2022/census_2022_products/Census_2022_Statistical_release.pdf', 'Census 2022 gives the definitive snapshot. The General Household Survey (GHS P0318) updates service delivery indicators annually. Update by running: python scripts/update_housing.py', '2001', '2022'),
    ('housing', 'housing-electricity', 'Households with Electricity', 'Percentage of households connected to the electrical grid as per Census 2022. Despite near-universal connectivity, load-shedding (scheduled power cuts) severely impacts effective access and remains a major economic drag.', 'housing', 1, '%', 'decennial', 'manual', 'national', 'Census 2022 Statistical Release', 'https://www.statssa.gov.za/census/census_2022/census_2022_products/Census_2022_Statistical_release.pdf', 'Census 2022 gives the definitive snapshot. The General Household Survey (GHS P0318) updates service delivery indicators annually. Update by running: python scripts/update_housing.py', '2001', '2022'),
    ('housing', 'housing-formal-dwellings', 'Households in Formal Dwellings', 'Percentage of households living in formal dwellings (brick/concrete houses, flats, townhouses) as per Census 2022. Approximately 14.8% live in informal dwellings (shacks). Gauteng has the highest proportion of informal settlements.', 'housing', 1, '%', 'decennial', 'manual', 'national', 'Census 2022 Statistical Release', 'https://www.statssa.gov.za/census/census_2022/census_2022_products/Census_2022_Statistical_release.pdf', 'Census 2022 gives the definitive snapshot. The General Household Survey (GHS P0318) updates service delivery indicators annually. Update by running: python scripts/update_housing.py', '2001', '2022'),
    ('census', 'census-households', 'Total Households', 'Total private households counted in Census 2022. Average household size has declined from 3.4 persons in 2011 to 3.0 in 2022, reflecting changing family structures and increasing urbanisation.', 'census', 1, 'households', 'decennial', 'static', 'national', 'Census 2022 Statistical Release', 'https://www.statssa.gov.za/census/census_2022/census_2022_products/Census_2022_Statistical_release.pdf', 'Census 2022 data is static until the next census. No automation needed. These figures are definitive.', '2001', '2022'),
    ('census', 'census-internet-access', 'Households with Internet Access', 'Percentage of households with internet access (including mobile data) per Census 2022. In 2011 only 31% had access. The rapid expansion of mobile internet (4G/LTE) is the primary driver.', 'census', 1, '%', 'decennial', 'static', 'national', 'Census 2022 Statistical Release', 'https://www.statssa.gov.za/census/census_2022/census_2022_products/Census_2022_Statistical_release.pdf', 'Census 2022 data is static until the next census. No automation needed. These figures are definitive.', '2011', '2022'),
    ('census', 'census-no-income', 'Individuals with No Income', 'Percentage of individuals 15 years and older who reported no income in Census 2022. This includes the unemployed, students, and those who are economically inactive. The decline reflects expanding social grants and labour market changes.', 'census', 1, '%', 'decennial', 'static', 'national', 'Census 2022 Statistical Release', 'https://www.statssa.gov.za/census/census_2022/census_2022_products/Census_2022_Statistical_release.pdf', 'Census 2022 data is static until the next census. No automation needed. These figures are definitive.', NULL, NULL);

COMMIT;
